"use client";

import { useState } from "react";
import CatEyes from "../components/cateyes";
import Timer from "../components/Timer";
import HandTracker from "../components/HandTracker";

export default function Home() {
  const [mood, setMood] = useState<"normal" | "happy" | "angry">("normal");
  const [isWaving, setIsWaving] = useState(false);

  const handleTimerStateChange = (state: "idle" | "running" | "paused") => {
    switch (state) {
      case "idle":
        setMood("normal");
        break;
      case "running":
        setMood("happy");
        break;
      case "paused":
        setMood("angry");
        break;
    }
  };

  const handleWave = () => {
    setMood("happy");
    setIsWaving(true);
    setTimeout(() => setIsWaving(false), 2000);
  };

  return (
    <main className="min-h-screen flex flex-col items-center justify-center bg-[#000] overflow-hidden">
      <div className="flex flex-col items-center gap-12">
        <div className="relative">
          {isWaving && (
            <div className="absolute -top-24 left-1/2 -translate-x-1/2 text-white font-bold text-4xl animate-bounce">
              HI !! 👋
            </div>
          )}
          <CatEyes baseMood={mood} />
        </div>
        <Timer onStateChange={handleTimerStateChange} />
        <HandTracker onWave={handleWave} />
      </div>
    </main>
  );
}
