"use client";

import { useEffect, useRef, useState } from "react";
import { Hands, Results } from "@mediapipe/hands";
import { Camera } from "@mediapipe/camera_utils";

interface HandTrackerProps {
  onWave: () => void;
  isGreeting?: boolean;
}

export default function HandTracker({ onWave, isGreeting }: HandTrackerProps) {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isDetected, setIsDetected] = useState(false);

  // Wave detection states
  const waveCount = useRef(0);
  const lastWristX = useRef<number | null>(null);
  const lastWaveTime = useRef<number>(0);

  useEffect(() => {
    if (!videoRef.current || !canvasRef.current) return;

    const hands = new Hands({
      locateFile: (file) => `https://cdn.jsdelivr.net/npm/@mediapipe/hands/${file}`,
    });

    hands.setOptions({
      maxNumHands: 1,
      modelComplexity: 1,
      minDetectionConfidence: 0.5,
      minTrackingConfidence: 0.5,
    });

    const ctx = canvasRef.current.getContext("2d");

    hands.onResults((results: Results) => {
      if (!ctx || !canvasRef.current) return;

      ctx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);

      if (results.multiHandLandmarks && results.multiHandLandmarks.length > 0) {
        setIsDetected(true);
        const landmarks = results.multiHandLandmarks[0];

        // --- DRAW HAND ASSET (5 FINGERS) ---
        ctx.strokeStyle = "white";
        ctx.lineWidth = 4;
        ctx.lineCap = "round";
        ctx.lineJoin = "round";
        ctx.shadowBlur = 15;
        ctx.shadowColor = "rgba(255, 255, 255, 0.5)";

        // Connections for 5 fingers
        const connections = [
          [0, 1, 2, 3, 4],     // Thumb
          [0, 5, 6, 7, 8],     // Index
          [0, 9, 10, 11, 12],  // Middle
          [0, 13, 14, 15, 16], // Ring
          [0, 17, 18, 19, 20], // Pinky
          [5, 9, 13, 17, 0]    // Palm base
        ];

        connections.forEach(path => {
          ctx.beginPath();
          path.forEach((idx, i) => {
            const x = landmarks[idx].x * canvasRef.current!.width;
            const y = landmarks[idx].y * canvasRef.current!.height;
            if (i === 0) ctx.moveTo(x, y);
            else ctx.lineTo(x, y);
          });
          ctx.stroke();
        });

        // Draw points for joints
        ctx.fillStyle = "white";
        landmarks.forEach(p => {
          ctx.beginPath();
          ctx.arc(p.x * canvasRef.current!.width, p.y * canvasRef.current!.height, 3, 0, Math.PI * 2);
          ctx.fill();
        });

        // --- WAVE DETECTION ---
        const wristX = landmarks[0].x;
        const now = Date.now();

        if (lastWristX.current !== null) {
          const deltaX = wristX - lastWristX.current;
          // If moving fast horizontally
          if (Math.abs(deltaX) > 0.05 && now - lastWaveTime.current > 100) {
            waveCount.current += 1;
            lastWaveTime.current = now;

            if (waveCount.current > 3) {
              onWave();
              waveCount.current = 0;
            }
          }
        }
        lastWristX.current = wristX;

      } else {
        setIsDetected(false);
        waveCount.current = 0;
      }
    });

    const camera = new Camera(videoRef.current, {
      onFrame: async () => {
        if (videoRef.current) {
          await hands.send({ image: videoRef.current });
        }
      },
      width: 640,
      height: 480,
    });

    camera.start();

    return () => {
      camera.stop();
      hands.close();
    };
  }, [onWave]);

  return (
    <div className="hand-container fixed bottom-8 right-8 pointer-events-none">
      <video ref={videoRef} className="hidden" playsInline autoPlay />
      <div className={`transition-opacity duration-500 ${isDetected ? 'opacity-100' : 'opacity-0'}`}>
        <canvas
          ref={canvasRef}
          width={280}
          height={210}
          className="rounded-xl bg-white/5 border border-white/10 backdrop-blur-sm"
        />
        <div className="text-[10px] text-white/40 uppercase tracking-[2px] mt-2 text-center">
          Hand Tracking Active
        </div>
      </div>
    </div>
  );
}
